    public async Task<FileUploadResult> UploadFileAsync(IFormFile file, FileUploadType uploadType)
    {
        if (file == null || file.Length == 0)
        {
            return FileUploadResult.Failure("No file provided or file is empty");
        }

        var config = AllowedConfigs[uploadType];

        if (file.Length > config.MaxSizeBytes)
        {
            return FileUploadResult.Failure($"File size exceeds maximum allowed size of {config.MaxSizeBytes / (1024 * 1024)}MB");
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (string.IsNullOrEmpty(extension) || !config.AllowedExtensions.Contains(extension))
        {
            return FileUploadResult.Failure($"File type not allowed. Allowed types: {string.Join(", ", config.AllowedExtensions)}");
        }

        if (!config.AllowedMimeTypes.Contains(file.ContentType.ToLowerInvariant()))
        {
            return FileUploadResult.Failure("Invalid content type");
        }

        if (!await ValidateFileSignatureAsync(file, extension, config))
        {
            return FileUploadResult.Failure("File content does not match the file extension");
        }

        var safeFileName = GenerateSafeFileName(file.FileName, extension);
        var uploadPath = Path.Combine("wwwroot", "uploads", config.SubDirectory);

        if (!Directory.Exists(uploadPath))
        {
            Directory.CreateDirectory(uploadPath);
        }

        var filePath = Path.Combine(uploadPath, safeFileName);
        var relativePath = Path.Combine("uploads", config.SubDirectory, safeFileName).Replace("\\", "/");

        try
        {
            using (var stream = new FileStream(filePath, FileMode.Create, FileAccess.Write, FileShare.None, 4096, useAsync: true))
            {
                await file.CopyToAsync(stream);
            }

            return FileUploadResult.Success(relativePath, safeFileName, file.Length);
        }
        catch (Exception ex)
        {
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
            }

            return FileUploadResult.Failure($"Error saving file: {ex.Message}");
        }
    }

    private async Task<bool> ValidateFileSignatureAsync(IFormFile file, string extension, AllowedFileConfig config)
    {
        if (!config.MagicNumbers.ContainsKey(extension))
        {
            return true;
        }

        var signatures = config.MagicNumbers[extension];
        var maxSignatureLength = signatures.Max(s => s.Length);

        using (var reader = new BinaryReader(file.OpenReadStream()))
        {
            var headerBytes = reader.ReadBytes(maxSignatureLength);

            return signatures.Any(signature =>
                headerBytes.Take(signature.Length).SequenceEqual(signature));
        }
    }

    private string GenerateSafeFileName(string originalFileName, string extension)
    {
        var fileNameWithoutExtension = Path.GetFileNameWithoutExtension(originalFileName);
        var safeFileName = string.Concat(fileNameWithoutExtension.Where(c => char.IsLetterOrDigit(c) || c == '-' || c == '_'));

        if (string.IsNullOrWhiteSpace(safeFileName))
        {
            safeFileName = "file";
        }

        if (safeFileName.Length > 50)
        {
            safeFileName = safeFileName.Substring(0, 50);
        }

        var uniqueId = Guid.NewGuid().ToString("N").Substring(0, 8);
        return $"{safeFileName}_{uniqueId}{extension}";
    }
